import{_ as t,o as a,c as r,ae as i}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Creatives Optimization","description":"","frontmatter":{"title":"Creatives Optimization","slug":"creatives-optimization"},"headers":[],"relativePath":"marketer-hub/creatives-optimization.md","filePath":"marketer-hub/creatives-optimization.md"}'),n={name:"marketer-hub/creatives-optimization.md"};function o(s,e,h,d,c,l){return a(),r("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><a href="https://dashboard.branch.io/journeys/creatives-optimization" target="_blank" rel="noreferrer">Creatives Optimization</a> is a tab in the Branch Dashboard related to Journeys. With it, you can measure the performance of your web-to-app banner campaigns to better understand their effectiveness. You&#39;ll be able to understand which creative drove the most conversions and leverage these insights to make more informed decisions around Journeys A/B testing. More specifically, Creatives Optimization will unlock the following features:</p><ul><li>Easily increase the % of views for the higher converting creative.</li><li>Gain a historical understanding of the A/B test since the experiment started.</li><li>See a simplified data view to better understand the performance of multiple creatives with a Journey.</li></ul><h2 id="initializing-creatives-optimization" tabindex="-1">Initializing Creatives Optimization <a class="header-anchor" href="#initializing-creatives-optimization" aria-label="Permalink to &quot;Initializing Creatives Optimization&quot;">​</a></h2><p>Before analyzing A/B test performance, you must first have an active Journeys campaign with multiple creatives active. If you do not have one created yet, <a href="https://dashboard.branch.io/journeys/audiencerule/new" target="_blank" rel="noreferrer">create a new Journey</a> in the Branch Dashboard.</p><p>Additional details on creating Journeys banners/interstitials can be viewed in the guide <a href="./create-journey-banner-or-interstitial.html"><strong>here</strong></a>.</p><h2 id="measuring-performance" tabindex="-1">Measuring Performance <a class="header-anchor" href="#measuring-performance" aria-label="Permalink to &quot;Measuring Performance&quot;">​</a></h2><p>Once your Journeys campaign is launched and users are downloading your app from the original banner/interstitial, you&#39;ll be able to measure the performance of your A/B test in the <a href="https://dashboard.branch.io/journeys/creatives-optimization" target="_blank" rel="noreferrer">Creatives Optimization</a> screen of the Branch Dashboard. For each Journeys campaign active with multiple creatives, you&#39;ll be able to see its performance here from its last updated date.</p><h4 id="definitions" tabindex="-1">Definitions <a class="header-anchor" href="#definitions" aria-label="Permalink to &quot;Definitions&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Performance Stat</th><th>Definition</th></tr></thead><tbody><tr><td>Creative Name</td><td>The name of the creative.</td></tr><tr><td>Audience</td><td>The percentage of your audience targeted with a creative.</td></tr><tr><td>Unique Users</td><td>The number of unique users that have viewed a creative.</td></tr><tr><td>Installs</td><td>The number of installs attributed to a creative.</td></tr><tr><td>Conversion Rate</td><td>The average conversion rate you can expect from a creative.</td></tr><tr><td>Probability to be Best</td><td>Chances that a creative would perform better than others.</td></tr><tr><td>Last Updated Date</td><td>Refers to the last time there was a change to the Journey that affected the experiment. Examples include changing the audience percentages or updating the design of a creative.</td></tr></tbody></table><p>When looking at the performance, you can see which creative is likely to be the better performing one over time through the <strong>PROBABILITY TO BE BEST</strong> column. From here, you can adjust the percentages for your A/B test directly below it.</p>',11)])])}const p=t(n,[["render",o]]);export{m as __pageData,p as default};
